import json
from flask import Flask, request, jsonify
from PIL import Image
import numpy as np
from tensorflow.keras.preprocessing.image import img_to_array
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Dense, Dropout, Flatten
from sklearn.metrics import accuracy_score
from tensorflow.keras.utils import to_categorical

app = Flask(__name__)

# Load model architecture
model = Sequential()
model.add(Flatten(input_shape=(224, 224, 3)))
model.add(Dense(128, activation='relu'))
model.add(Dropout(0.2))
model.add(Dense(10, activation='softmax'))

# Load labeled data (initially empty)
labels = {}

# Route for annotator to submit label
@app.route('/label', methods=['POST'])
def submit_label():
    data = request.get_json()
    image_id = data['image_id']
    annotation = data['annotation']

    if image_id not in labels:
        labels[image_id] = []

    labels[image_id].append(annotation)

    # Aggregate labels using majority voting
    aggregated_annotation = max(set(labels[image_id]), key=labels[image_id].count)
    print(f'Aggregated label for {image_id}: {aggregated_annotation}')

    return jsonify({'status': 'ok'})

# Route to train model on labeled data
@app.route('/train', methods=['POST'])
def train_model():
    # Aggregate labels from all images
    aggregated_labels = {}
    for image_id, annotations in labels.items():
        aggregated_label = max(set(annotations), key=annotations.count)
        aggregated_labels[image_id] = aggregated_label

    # Convert aggregated labels to categorical format
    aggregated_labels_cat = to_categorical(aggregated_labels)

    # Prepare training data (initially empty)
    train_data = []
    train_targets = []

    # Add training examples from labeled images
    for image_id, annotation in aggregated_labels.items():
        image_path = f'path/to/image/{image_id}.jpg'
        img = Image.open(image_path).resize((224, 224))
        arr = img_to_array(img)
        train_data.append(arr)
        train_targets.append(annotation)

    # Train model
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    model.fit(np.array(train_data), np.array(train_targets), epochs=10, batch_size=32, verbose=0)

    return jsonify({'status': 'ok'})

if __name__ == '__main__':
    app.run(debug=True)